@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";
@import "./tokens/colors.css";

@custom-variant dark (&:is(.dark *));

:root {
  --background: oklch(100% 0 0); /* #FFFFFF */
  --foreground: oklch(20.46% 0 0); /* #171717 */ /*ink/gray-8*/

  --card: oklch(100% 0 0); /* #FFFFFF */ /*surface/card*/
  --card-foreground: oklch(68.3% 0 0); /* #999999 */ /*ink/gray-4*/

  --popover: oklch(100% 0 0); /* #FFFFFF */ /*surface/modal*/
  --popover-foreground: oklch(82.97% 0 0); /* #c7c7c7 */ /*ink/gray-3*/

  --primary: oklch(20.46% 0 0); /* #171717 */ /*surface/gray-7*/
  --primary-foreground: oklch(100% 0 0); /* #FFFFFF */ /*ink/white*/

  --secondary: oklch(96.42% 0 0); /* #F3F3F3 */ /*surface/gray-2*/
  --secondary-foreground: oklch(34.07% 0 0); /* #383838 */ /*ink/gray-7*/

  --muted: oklch(94.61% 0 0); /* #EDEDED */ /*surface/gray-3*/
  --muted-foreground: oklch(43.86% 0 0); /* #525252 */ /*ink/gray-6*/

  --accent: oklch(91.28% 0 0); /* #E2E2E2 */ /*surface/gray-4*/
  --accent-foreground: oklch(58.63% 0 0); /* #7c7c7c */ /*ink/gray-5*/

  --destructive: oklch(55.03% 0.199 26.77); /* #CC2929 */ /*surface/red-5*/
  --destructive-foreground: oklch(
    98.23% 0.009 17.3
  ); /* #fff7f7 */ /*ink/red-1*/

  --border: oklch(91.28% 0 0); /* #E2E2E2 */ /*outline/gray-2*/
  --input: oklch(97.91% 0 0); /* #f8f8f8 */ /*surface/gray-1*/

  --chart-1: oklch(0.809 0.105 251.813);
  --chart-2: oklch(0.623 0.214 259.815);
  --chart-3: oklch(0.546 0.245 262.881);
  --chart-4: oklch(0.488 0.243 264.376);
  --chart-5: oklch(0.424 0.199 265.638);

  --ring: oklch(0.8359 0.0001 263.28 / 0.5647); /* #c9c9c990 */
  --sidebar: oklch(0.9791 0.0001 263.28); /* #f8f8f8 */
  --sidebar-foreground: oklch(0.4386 0 263.28); /* #525252 */
  --sidebar-primary: oklch(0.2046 0 263.28); /* #171717 */
  --sidebar-primary-foreground: oklch(1 0.0001 263.28); /* #ffffff */
  --sidebar-accent: oklch(0.9461 0.0001 263.28); /* #ededed */
  --sidebar-accent-foreground: oklch(0.4386 0 263.28); /* #525252 */
  --sidebar-border: oklch(0.9461 0.0001 263.28); /* #ededed */
  --sidebar-ring: oklch(0.8359 0.0001 263.28 / 0.5647); /* #c9c9c990 */

  --surface: oklch(100% 0 0); /* #FFFFFF */ /*surface/selected*/
  --code-highlight: lab(95.36% 0 0);
  --code-number: lab(48.96% 0 0);
  --selection: lab(2.75381% 0 0);
  --selection-foreground: lab(100% 0 0);

  /* start custom variables */
  --destructive-hover: oklch(0.4906 0.1801 27.06); /* #B52A2A */
  --destructive-active: oklch(0.3998 0.1474 27.42); /* #941F1F */
  --destructive-disabled: oklch(0.9351 0.0268 17.5); /* #FFE7E7 */
  --destructive-disabled-foreground: oklch(0.7468 0.0856 18.72); /* #F79596 */
  --success: oklch(96.49% 0.03 155.99); /* #E4FAEB */ /*surface/green-2*/
  --success-foreground: oklch(
    50.94% 0.116 156.33
  ); /* #137949 */ /*ink/green-4*/
  --error: oklch(94.73% 0.026 17.63); /* #FFE7E7 */ /*surface/red-2*/
  --error-foreground: oklch(50.95% 0.176 26.08); /* #B52A2A */ /*ink/red-4*/
  --filled: oklch(96.18% 0.023 56.96); /* #FFEFE4 */ /*surface/orange-2*/
  --warning: oklch(97.32% 0.047 96.81); /* #FFF7D3 */ /*surface/amber-2*/
  --warning-foreground: oklch(55.38% 0.145 49.26); /* #B35309 */ /*ink/amber-4*/
  --info: oklch(96% 0.021 241.35); /* #E6F4FF */ /*surface/blue-2*/
  --info-foreground: oklch(54.42% 0.165 252.54); /* #0070CC */ /*ink/blue-4*/
  --success-outline: oklch(
    82.69% 0.135 154.7
  ); /* #78E09F */ /*outline/green-3*/
  --error-outline: oklch(77.17% 0.118 19.5); /* #F79596 */ /*outline/red-3*/
  --filled-outline: oklch(
    81.04% 0.102 56.49
  ); /* #F4B07F */ /*outline/orange-3*/
  --shadow-sm: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px 0 rgba(0, 0, 0, 0.06);
  --shadow-md: 0 0 1px 0 rgba(0, 0, 0, 0.14), 0 1px 3px 0 rgba(0, 0, 0, 0.14);
  --shadow-6xs:
    0 0 1.5px 0 rgba(0, 0, 0, 0.16), 0 2px 5px 0 rgba(0, 0, 0, 0.14); /* elevation/light/base */
  --shadow-5xs:
    0 0 1px 0 rgba(0, 0, 0, 0.2), 0 0 10px 2px rgba(0, 0, 0, 0.04),
    0 24px 30px -8px rgba(0, 0, 0, 0.1);
  --shadow-4xs: 0 1px 4px 0 rgba(0, 0, 0, 0.1);
  --shadow-3xs: 0 0 0 2px rgba(201, 201, 201, 0.9);
  --shadow-xs: 0 3px 3px 0 rgba(0, 0, 0, 0.05);
  --shadow-lg: 0 0 0 2px #c7c7c7;
  --shadow-3xl:
    0 0 1.5px 0 rgba(0, 0, 0, 0.15), 0 0 6px 2px rgba(0, 0, 0, 0.03),
    0 6px 12px -2px rgba(0, 0, 0, 0.12); /* elevation/light/md */
  --shadow-4xl:
    0 0 2px 0 rgba(0, 0, 0, 0.2), 0 2px 7px 0 rgba(0, 0, 0, 0.1),
    0 0 0 2px #383838;
  --shadow-5xl:
    0 0 1.5px 0 rgba(0, 0, 0, 0.25), 0 0 10px 2px rgba(0, 0, 0, 0.03),
    0 44px 52px -10px rgba(0, 0, 0, 0.1); /* elevation/light/2xl */
  --border-soft: oklch(94.61% 0 0); /* #EDEDED */ /*outline/gray-1*/
  --border-normal: oklch(82.97% 0 0); /* #C7C7C7 */ /*outline/gray-3*/
  --border-strong: oklch(68.3% 0 0); /* #999999 */ /*outline/gray-4*/
  --border-stronger: oklch(34.07% 0 0); /* #383838 */ /*outline/gray-5*/
  /* end custom variables */

  --spacing: 0.25rem; /* 4px */

  --radius: 0.625rem; /* 10px */

  /* font weights */
  --font-weight-light: 300;
  --font-weight-normal: 420;
  --font-weight-medium: 500;
  --font-weight-medium-plus: 530;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-extrabold: 800;

  /* font sizes */
  --text-tiny: 0.6875rem; /* 11px */
  --text-tiny--line-height: 0;
  --text-2xs: 0.6875rem; /* 11px */
  --text-2xs--line-height: 1.1818;
  --text-xs: 0.75rem; /* 12px */
  --text-xs--line-height: 1.1667;
  --text-sm: 0.8125rem; /* 13px */
  --text-sm--line-height: 1.1538;
  --text-base: 0.875rem; /* 14px */
  --text-base--line-height: 1.1429;
  --text-lg: 1rem; /* 16px */
  --text-lg--line-height: 1.125;
  --text-xl: 1.125rem; /* 18px */
  --text-xl--line-height: 1.1667;
  --text-2xl: 1.25rem; /* 20px */
  --text-2xl--line-height: 1.15;
  --text-3xl: 1.5rem; /* 24px */
  --text-3xl--line-height: 1.1667;
  --text-4xl: 1.625rem; /* 26px */
  --text-4xl--line-height: 1.6154;
  --text-5xl: 1.75rem; /* 28px */
  --text-5xl--line-height: 1.6071;
  --text-6xl: 2rem; /* 32px */
  --text-6xl--line-height: 1.5938;
  --text-7xl: 2.5rem; /* 40px */
  --text-7xl--line-height: 1.4;
  --text-8xl: 2.75rem; /* 44px */
  --text-8xl--line-height: 1.4091;
  --text-9xl: 3rem; /* 48px */
  --text-9xl--line-height: 1.3958;
  --text-10xl: 3.25rem; /* 52px */
  --text-10xl--line-height: 1.4038;
  --text-11xl: 3.5rem; /* 56px */
  --text-11xl--line-height: 1.3929;
  --text-12xl: 4rem; /* 64px */
  --text-12xl--line-height: 1.2969;
  --text-13xl: 4.5rem; /* 72px */
  --text-13xl--line-height: 1.2778;
  --text-14xl: 5rem; /* 80px */
  --text-14xl--line-height: 1.2;
  --text-15xl: 5.5rem; /* 88px */
  --text-15xl--line-height: 1.2045;

  /* line heights */
  --leading-tiny: 0;
  --leading-2xs: 1.18;
  --leading-xs: 1.17;
  --leading-sm: 1.15;
  --leading-base: 1.15;
  --leading-lg: 1.13;
  --leading-xl: 1.17;
  --leading-2xl: 1.15;
  --leading-3xl: 1.17;
  --leading-4xl: 1.62;
  --leading-5xl: 1.61;
  --leading-6xl: 1.59;
  --leading-7xl: 1.4;
  --leading-8xl: 1.41;
  --leading-9xl: 1.4;
  --leading-10xl: 1.4;
  --leading-11xl: 1.39;
  --leading-12xl: 1.3;
  --leading-13xl: 1.28;
  --leading-14xl: 1.2;
  --leading-15xl: 1.2;
  --leading-tight: 1.25;
  --leading-snug: 1.375;
  --leading-normal: 1.5;
  --leading-relaxed: 1.625;
  --leading-loose: 2;

  /* border-radius */
  --radius-3xs: 0.125rem; /* 2px */
  --radius-2xs: calc(var(--radius) * 0.4); /* 4px */
  --radius-xs: calc(var(--radius) * 0.5); /* 5px */
  --radius-sm: calc(var(--radius) * 0.6); /* 6px */
  --radius-md: calc(var(--radius) * 0.8); /* 8px  */
  --radius-lg: var(--radius); /* 10px */
  --radius-xl: calc(var(--radius) * 1.2); /* 12px */
  --radius-2xl: calc(var(--radius) * 1.4); /* 14px */
  --radius-3xl: calc(var(--radius) * 1.6); /* 16px */
  --radius-4xl: calc(var(--radius) * 2); /* 20px */
  --radius-5xl: calc(var(--radius) * 2.4); /* 24px */

  /* letter spacing */
  --tracking-tighter: -0.05em;
  --tracking-tight: -0.025em;
  --tracking-widest: 0.1em;
  --tracking-base: 0.02em;
  --tracking-normal: 0.015em;
}

.dark {
  --background: oklch(0% 0 0); /* #000000 */
  --foreground: oklch(97.91% 0 0); /* #F8F8F8 */ /*ink/gray-8*/
  --card: oklch(22.64% 0 0); /* #1C1C1C */ /*surface/card*/
  --card-foreground: oklch(54.86% 0 0); /* #717171 */ /*ink/gray-4*/
  --popover: oklch(25.62% 0 0); /* #232323 */ /*surface/modal*/
  --popover-foreground: oklch(45.68% 0 0); /* #575757 */ /*ink/gray-3*/

  --primary: oklch(97.91% 0 0); /* #F8F8F8 */ /*surface/gray-7*/
  --primary-foreground: oklch(16.84% 0 0); /* #0F0F0F */ /*ink/white*/
  --secondary: oklch(28.91% 0 0); /* #2B2B2B */ /*surface/gray-2*/
  --secondary-foreground: oklch(88.53% 0 0); /* #D9D9D9 */ /*ink/gray-7*/

  --muted: oklch(32.5% 0 0); /* #343434 */ /*surface/gray-3*/
