  --accent: oklch(37.91% 0 0); /* #424242 */ /*surface/gray-4*/
  --accent-foreground: oklch(59.99% 0 0); /* #808080 */ /*ink/gray-5*/

  --destructive: oklch(49.06% 0.18 27.06); /* #B01F1F */ /*surface/red-5*/
  --destructive-foreground: oklch(100% 0 0); /* #FFFFFF */ /*ink/red-1*/

  /* start custom variables */
  --destructive-hover: oklch(57.78% 0.201 26.24); /* #D73232 */
  --destructive-active: oklch(41.25% 0.137 25.6); /* #862020 */
  --destructive-disabled: oklch(25.37% 0.065 18.58); /* #3C1316 */
  --destructive-disabled-foreground: oklch(34.06% 0.112 25.44); /* #661717 */
