    73.25% 0.122 160.22
  ); /* #58C08E */ /*ink/green-4*/
  --error: oklch(25.37% 0.065 18.58); /* #3C1316 */ /*surface/red-2*/
  --error-foreground: oklch(64.13% 0.194 22.78); /* #EB4D52 */ /*ink/red-4*/
  --filled: oklch(25.78% 0.051 54.3); /* #361C09 */ /*surface/orange-2*/
  --warning: oklch(26.34% 0.053 60.93); /* #371E06 */ /*surface/amber-2*/
  --warning-foreground: oklch(76.14% 0.166 62.77); /* #FA961F */ /*ink/amber-4*/
  --info: oklch(24.14% 0.05 255.39); /* #0E2037 */ /*surface/blue-2*/
  --info-foreground: oklch(72.68% 0.129 245.33); /* #5AAEF2 */ /*ink/blue-4*/
  --success-outline: oklch(
    40.52% 0.098 155.47
  ); /* #035831 */ /*outline/green-3*/
  --error-outline: oklch(34.06% 0.112 25.44); /* #661717 */ /*outline/red-3*/
  --filled-outline: oklch(
    38.04% 0.093 50.98
  ); /* #683108 */ /*outline/orange-3*/
  --shadow-5xs:
    0 0.5px 1.5px 0.5px rgba(255, 255, 255, 0.04) inset,
    0 0 14px 2px rgba(0, 0, 0, 0.12), 0 26px 34px -6px rgba(0, 0, 0, 0.42);

  --border-soft: oklch(25.62% 0 0); /* #232323 */ /*outline/gray-1*/
  --border-normal: oklch(37.91% 0 0); /* #424242 */ /*outline/gray-3*/
  --border-strong: oklch(45.68% 0 0); /* #575757 */ /*outline/gray-4*/
  --border-stronger: oklch(94.61% 0 0); /* #EDEDED */ /*outline/gray-5*/
  /* end custom variables */

  --border: oklch(32.5% 0 0); /* #343434 */ /*outline/gray-2*/
  --input: oklch(25.62% 0 0); /* #232323 */ /*surface/gray-1*/

  --chart-1: oklch(0.809 0.105 251.813);
  --chart-2: oklch(0.623 0.214 259.815);
  --chart-3: oklch(0.546 0.245 262.881);
  --chart-4: oklch(0.488 0.243 264.376);
  --chart-5: oklch(0.424 0.199 265.638);

  --ring: oklch(0.8359 0.0001 263.28 / 0.5647); /* #c9c9c990 */
  --sidebar: oklch(0.1684 0 263.28); /* #0f0f0f */
  --sidebar-foreground: oklch(0.754 0.0001 263.28); /* #afafaf */
  --sidebar-primary: oklch(0.2046 0 263.28); /* #171717 */
  --sidebar-primary-foreground: oklch(1 0.0001 263.28); /* #ffffff */
  --sidebar-accent: oklch(0.325 0 263.28); /* #343434 */
  --sidebar-accent-foreground: oklch(0.754 0.0001 263.28); /* #afafaf */
  --sidebar-border: oklch(0.2562 0 263.28); /* #232323 */
  --sidebar-ring: oklch(0.8359 0.0001 263.28 / 0.5647); /* #c9c9c990 */

  --surface: oklch(32.5% 0 0); /* #343434 */ /*surface/selected*/
  --code-highlight: lab(95.36% 0 0);
  --code-number: lab(48.96% 0 0);
  --selection: lab(2.75381% 0 0);
  --selection-foreground: lab(100% 0 0);
}

@theme inline {
  --font-sans: var(--font-sans);
  /* Variations Fonts */
  --font-sans--font-variation-settings: "opsz" 24;

  /* Fonts Weight */
  --font-sans-weight: 420;
  --font-weight-light: var(--font-weight-light);
  --font-weight-normal: var(--font-weight-normal);
  --font-weight-medium: var(--font-weight-medium);
  --font-weight-medium-plus: var(--font-weight-medium-plus);
  --font-weight-semibold: var(--font-weight-semibold);
  --font-weight-bold: var(--font-weight-bold);
  --font-weight-extrabold: var(--font-weight-extrabold);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-surface: var(--surface);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-border-soft: var(--border-soft);
  --color-border-normal: var(--border-normal);
  --color-border-strong: var(--border-strong);
  --color-border-stronger: var(--border-stronger);
  --color-destructive: var(--destructive);
  --color-destructive-hover: var(--destructive-hover);
  --color-destructive-active: var(--destructive-active);
  --color-destructive-disabled: var(--destructive-disabled);
  --color-destructive-disabled-foreground: var(
    --destructive-disabled-foreground
  );
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-error: var(--error);
  --color-error-foreground: var(--error-foreground);
  --color-filled: var(--filled);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-info: var(--info);
  --color-info-foreground: var(--info-foreground);
  --color-success-outline: var(--success-outline);
  --color-error-outline: var(--error-outline);
  --color-filled-outline: var(--filled-outline);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --color-foreground: var(--foreground);
  --color-background: var(--background);

  --radius-3xs: 0.125rem;
  --radius-2xs: calc(var(--radius) * 0.4);
  --radius-xs: calc(var(--radius) * 0.5);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.2);
  --radius-2xl: calc(var(--radius) * 1.4);
  --radius-3xl: calc(var(--radius) * 1.6);
  --radius-4xl: calc(var(--radius) * 2);
  --radius-5xl: calc(var(--radius) * 2.4);

  /* shadows */
  --shadow-6xs: var(--shadow-6xs);
  --shadow-5xs: var(--shadow-5xs);
  --shadow-4xs: var(--shadow-4xs);
  --shadow-3xs: var(--shadow-3xs);
  --shadow-xs: var(--shadow-xs);
  --shadow-sm: var(--shadow-sm);
  --shadow-md: var(--shadow-md);
  --shadow-lg: var(--shadow-lg);
  --shadow-3xl: var(--shadow-3xl);
  --shadow-4xl: var(--shadow-4xl);
  --shadow-5xl: var(--shadow-5xl);

  /* font sizes */
  --text-tiny: var(--text-tiny);
